                            context.EvaluatedKeywordForProperty(true, 33, RequiredPropertyTerminalStatusPresent, "terminalStatus"u8, "required"u8);
                            context.EvaluatedKeywordForProperty(true, 34, RequiredPropertyUsagePresent, "usage"u8, "required"u8);
                        }
                    }
                    else if (!context.HasCollector)
                    {
                        context.EvaluatedBooleanSchema(false);
                        return;
                    }
                    else
                    {
                        if ((requiredPropertyChildHandler_seenItems[RequiredOffsetForTenantHash] & RequiredBitForTenantHash) == 0)
                        {
                            context.EvaluatedKeywordForProperty(false, 32, RequiredPropertyTenantHashNotPresent, "tenantHash"u8, "required"u8);
                        }
                        else
                        {
                            context.EvaluatedKeywordForProperty(true, 32, RequiredPropertyTenantHashPresent, "tenantHash"u8, "required"u8);
                        }

                        if ((requiredPropertyChildHandler_seenItems[RequiredOffsetForTerminalStatus] & RequiredBitForTerminalStatus) == 0)
                        {
                            context.EvaluatedKeywordForProperty(false, 33, RequiredPropertyTerminalStatusNotPresent, "terminalStatus"u8, "required"u8);
                        }
                        else
                        {
                            context.EvaluatedKeywordForProperty(true, 33, RequiredPropertyTerminalStatusPresent, "terminalStatus"u8, "required"u8);
                        }

                        if ((requiredPropertyChildHandler_seenItems[RequiredOffsetForUsage] & RequiredBitForUsage) == 0)
                        {
                            context.EvaluatedKeywordForProperty(false, 34, RequiredPropertyUsageNotPresent, "usage"u8, "required"u8);
                        }
                        else
                        {
                            context.EvaluatedKeywordForProperty(true, 34, RequiredPropertyUsagePresent, "usage"u8, "required"u8);
                        }
                    }
                }
            }

            internal static bool Evaluate(
                IJsonDocument parentDocument,
                int parentIndex,
                IJsonSchemaResultsCollector? resultsCollector = null)
            {
                JsonSchemaContext context = JsonSchemaContext.BeginContext(
                parentDocument,
                parentIndex,
                usingEvaluatedItems: false,
                usingEvaluatedProperties: true,
                resultsCollector: resultsCollector);
                try
                {
                    Evaluate(parentDocument, parentIndex, ref context);
                    context.EndContext();
                    return context.IsMatch;
                }
                finally
                {
                    context.Dispose();
                }
            }

